#[tokio::test]
async fn test_init_machine_rejects_reinit() {
    // 1. Call init_machine — succeeds
    program.rpc().process_transaction(&init_tx).await.unwrap();
    // 2. Close the account (lamports refunded to authority)
    program.rpc().process_transaction(&close_tx).await.unwrap();
    // 3. Refund / recreate account at same PDA
    program.rpc().process_transaction(&refund_tx).await.unwrap();
    // 4. Call init_machine again — must fail
    let result = program.rpc().process_transaction(&init_tx_2).await;
    assert!(result.is_err()); // Must fail with ReinitDetected or AccountAlreadyInitialized
}

#[tokio::test]
async fn test_set_authority_requires_current_authority_signature() {
    // Attacker passes mint_account they found but does NOT sign with its current authority
    let malicious_tx = Transaction::new_signed_with_payer(
        &[instruction::set_authority(&program_id, &mint_account, &attacker.pubkey())],
        Some(&attacker.pubkey()),
        &[&attacker], // Attacker signs — NOT the current mint authority
        recent_blockhash,
    );
    let result = program.rpc().process_transaction(&malicious_tx).await;
    assert!(result.is_err()); // Must fail — attacker is not the current authority
}

