#[test]
fn test_overflow_returns_error() {
    let mut total: u32 = 0;
    let result = total.checked_add(u32::MAX);
    assert!(result.is_none(), "checked_add must return None on overflow");
    // Verify wrapping_add silently wraps — use checked_add in production
    let wrapped = total.wrapping_add(u32::MAX);
    assert_eq!(wrapped, u32::MAX.wrapping_add(0));
}

#[tokio::test]
async fn test_mint_callback_reentrancy_guard() {
    // Deploy a malicious program that re-enters mint_with_callback from a CPI callback
    let reentrant_tx = Transaction::new_signed_with_payer(
        &[instruction::mint_with_callback(&program_id, &callback_accounts)],
        Some(&user.pubkey()),
        &[&user],
        recent_blockhash,
    );
    let result = program.rpc().process_transaction(&reentrant_tx).await;
    // Verify items_redeemed was incremented exactly once
    let machine = program.account::<CandyMachine>(machine_pubkey).await;
    assert_eq!(machine.items_redeemed, 1); // Not 2, not 0
}

#[tokio::test]
async fn test_transfer_nft_accounts_for_fees() {
    // Create a Token-2022 mint with transfer fees enabled
    // Call transfer_nft with amount = 1000
    // Verify recipient received amount - fee, not amount
    let recipient_balance = get_token_balance(recipient).await;
    let fee_config = get_transfer_fee_config(&mint).await;
    let expected_net = 1000u64 - fee_config.calculate_fee(1000);
    assert_eq!(recipient_balance, expected_net);
}

